+func TestMailTypeValidation(t *testing.T) {
+	tmpDir := t.TempDir()
+	testStore := newTestStore(t, tmpDir+"/.beads/beads.db")
+	ctx := context.Background()
+
+	// Create a regular issue (not a message)
